from concurrent.futures import ThreadPoolExecutor, as_completed
from typing import Any, Dict, List, Optional, Tuple
from datetime import datetime
from models.selector_model import SelectorModel
from models.verifier_model import VerifierModel
from models.final_judge_model import FinalJudgeModel
###############################################################################
# Config (infra defaults)
###############################################################################
api_base = "http://10.102.250.34:10028/v1"
project = "ailab-intern11"
name = "lizehao"
rjob_task = "lizehao-w7zrs-380058-worker-0"
