base_url = f"https://h.pjlab.org.cn/kapi/workspace.kubebrain.io/{project}/{rjob_task}.{name}/{port}/v1"
base_url = "https://api.boyuerichdata.opensphereai.com/v1"
ak = "157d08870053a85595203ad7b5937293"
sk = "488d1f99b9b2956fb9a41693cc15aa5b"
MAX_SELECTOR_ROUNDS = 6
MAX_WORKERS = 8  # FIXED
MAX_SELECTOR_INITIAL_RETRIES = 2
MAX_SELECTOR_FOLLOW_RETRIES = 2
FALLBACK_KEY_STEPS_COUNT = 3
DEFAULT_MODE = os.getenv("MULTI_AGENT_MODE", "completion")  # completion | next_action | all
###############################################################################
# Utilities
###############################################################################
def now_iso() -> str:
    return datetime.now().isoformat(timespec="seconds")
def ensure_output_dir(path: str) -> None:
    os.makedirs(path, exist_ok=True)
def read_jsonl(path: str) -> List[Dict[str, Any]]:
    items: List[Dict[str, Any]] = []
    with open(path, "r", encoding="utf-8") as f:
        for line_no, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
            except json.JSONDecodeError as e:
                raise ValueError(f"Invalid JSONL at {path}:{line_no}: {e}")
            if isinstance(obj, dict):
                items.append(obj)
    return items
def resolve_path(maybe_path: str, base_dir: str) -> str:
    if not isinstance(maybe_path, str) or not maybe_path:
        return ""
    if os.path.isabs(maybe_path):
        return maybe_path
    return os.path.abspath(os.path.join(base_dir, maybe_path))
def safe_relpath(path: Optional[str], start: str) -> Optional[str]:
    if not path:
        return None
    try:
        return os.path.relpath(path, start)
    except Exception:
        return path
def extract_tag_content(response: str, tag: str) -> str:
    pattern = re.compile(rf"<{tag}>\s*(.*?)\s*</{tag}>", re.DOTALL)
    match = pattern.search(response or "")
    return match.group(1).strip() if match else ""
def extract_qwen_sections(response: str) -> Tuple[str, str, str]:
    """Parse Qwen-style blocks (Thought/Action/tool_call) when XML tags are absent."""
    if not isinstance(response, str):
        return "", "", ""
    def capture_block(label: str) -> str:
        pattern = re.compile(
            rf"{label}:\s*(.*?)(?:\n[A-Za-z ]+?:|<tool_call>|$)",
            re.DOTALL,
        )
        match = pattern.search(response)
        return match.group(1).strip() if match else ""
    think = capture_block("Thought")
    operation = capture_block("Action")
    tool_match = re.search(r"<tool_call>\s*(.*?)\s*</tool_call>", response, re.DOTALL)
    action = tool_match.group(1).strip() if tool_match else ""
    return think, operation, action
def safe_parse_response(model, raw_response: str) -> Optional[Any]:
    if isinstance(raw_response, (dict, list)):
        return raw_response
    try:
        return model.parse_response(raw_response)
    except Exception as exc:
        print(f"[{model.name}] Failed to parse response: {exc}\nRaw: {raw_response}")
        return None
def normalize_selector_response_text(text: Optional[str]) -> str:
    if not isinstance(text, str):
        return ""
    return " ".join(text.split())
def append_conversation_entry(
    conversation_log: List[Dict[str, Any]],
    model_name: str,
    text: str,
    selector_state: Dict[str, Any],
) -> None:
    available = True
    if model_name == "SelectorModel":
        normalized_text = normalize_selector_response_text(text)
        last_text = selector_state.get("last_text")
        waiting = selector_state.get("waiting_for_response", False)
        if waiting and normalized_text == last_text:
            available = False
        else:
            selector_state["last_text"] = normalized_text
        selector_state["waiting_for_response"] = True
    else:
        selector_state["waiting_for_response"] = False
    conversation_log.append({
        "model": model_name,
        "text": text,
        "available": available,
    })
def build_available_conversation(conversation_log: List[Dict[str, Any]]) -> List[Dict[str, str]]:
    """
    "Available" view: keeps dedup logic for SelectorModel; FinalJudgeModel always kept.
    Used for detailed final judge evidence.
    """
    available_entries: List[Dict[str, str]] = []
    for entry in conversation_log:
        if not entry.get("available", True) and entry.get("model") != "FinalJudgeModel":
            continue
        available_entries.append({
            "model": entry.get("model", ""),
            "text": entry.get("text", ""),
        })
    return available_entries
def build_all_model_responses(conversation_log: List[Dict[str, Any]]) -> List[Dict[str, str]]:
    """
    Compact log needs ALL model answers (no filtering).
    Keep only {model, text}.
    """
    out: List[Dict[str, str]] = []
    for entry in conversation_log:
        out.append({
            "model": entry.get("model", ""),
            "text": entry.get("text", ""),
        })
    return out
def format_json_for_prompt(data: Any) -> str:
    try:
        return json.dumps(data, ensure_ascii=False, indent=2)
    except (TypeError, ValueError):
        return json.dumps({"unserializable": True}, ensure_ascii=False)
def normalize_key_steps(selection: Optional[Dict[str, Any]]) -> List[Dict[str, Any]]:
    """Normalize selector outputs into a list of {step_index, assessment_goal, why_important} dicts."""
    if not isinstance(selection, dict):
        return []
    normalized_steps: List[Dict[str, Any]] = []
    raw_key_steps = selection.get("key_steps")
    if isinstance(raw_key_steps, list):
        for item in raw_key_steps:
            if not isinstance(item, dict):
                continue
            step_index = item.get("step_index")
            try:
                step_index_int = int(step_index)
            except (TypeError, ValueError):
                continue
            goal = (item.get("assessment_goal") or "").strip()
            why = (item.get("why_important") or "").strip()
            normalized_steps.append({
                "step_index": step_index_int,
                "assessment_goal": goal,
                "why_important": why,
            })
    if not normalized_steps:
        legacy_indices = selection.get("key_step_indices")
        if isinstance(legacy_indices, list):
            for idx in legacy_indices:
                try:
                    step_index_int = int(idx)
                except (TypeError, ValueError):
                    continue
                normalized_steps.append({
                    "step_index": step_index_int,
                    "assessment_goal": "",
                    "why_important": "",
                })
    deduped: List[Dict[str, Any]] = []
    seen: set[int] = set()
    for step in normalized_steps:
        idx = step["step_index"]
        if idx in seen:
            continue
        seen.add(idx)
        deduped.append(step)
    return deduped
def build_fallback_key_steps(
    step_lookup: Dict[int, Dict[str, Any]],
    max_steps: int = FALLBACK_KEY_STEPS_COUNT
) -> List[Dict[str, Any]]:
    """Heuristic fallback when the selector fails to provide any key steps."""
    if not step_lookup:
        return []
    sorted_indices = sorted(idx for idx in step_lookup.keys() if isinstance(idx, int))
    if not sorted_indices:
        return []
    terminal_step = sorted_indices[-1]
    candidate_indices = [idx for idx in sorted_indices if idx < terminal_step] or sorted_indices
    selected_indices = candidate_indices[-max_steps:]
    fallback_steps: List[Dict[str, Any]] = []
    for idx in selected_indices:
        record = step_lookup.get(idx, {})
        operation_desc = (
            record.get("operation")
            or record.get("action")
            or record.get("think")
            or ""
        )
        operation_desc = (operation_desc or "").strip()
        if len(operation_desc) > 160:
            operation_desc = operation_desc[:157] + "..."
        assessment_goal = f"Confirm that step {idx} achieved its intent: {operation_desc or 'intended operation'}."
        fallback_steps.append({
            "step_index": idx,
            "assessment_goal": assessment_goal,
            "why_important": "Fallback coverage for decisive recent steps.",
        })
    return fallback_steps
def get_step_image_pair(image_paths_1based: List[Optional[str]], step_index_1based: int) -> Tuple[Optional[str], Optional[str]]:
    """
    image_paths_1based: list with a dummy element at index 0; valid step screenshots at index 1..N.
    For step k: before = image_paths[k], after = image_paths[k+1]
    """
    if not image_paths_1based or len(image_paths_1based) <= 1:
        return None, None
    before_idx = step_index_1based
    after_idx = step_index_1based + 1
    before_path = image_paths_1based[before_idx] if 1 <= before_idx < len(image_paths_1based) else None
    after_path = image_paths_1based[after_idx] if 1 <= after_idx < len(image_paths_1based) else None
    print(f"step:{step_index_1based}, before_idx:{before_idx}, after_idx:{after_idx}, len:{len(image_paths_1based)}, before_path:{before_path}, after_path:{after_path}")
    return before_path, after_path
###############################################################################
# Summary (resume)
###############################################################################
def load_summary_bool(path: str) -> Dict[str, Any]:
    if os.path.exists(path):
        with open(path, "r", encoding="utf-8") as infile:
            try:
                data = json.load(infile)
                if isinstance(data, dict):
                    if "tasks" in data and isinstance(data["tasks"], dict):
                        return data
                    if all(isinstance(v, bool) for v in data.values()):
                        return {"tasks": data}
            except json.JSONDecodeError:
                pass
    return {"tasks": {}}
def write_summary_bool(path: str, summary: Dict[str, Any]) -> None:
    tasks = summary.get("tasks", {})
    payload = {"tasks": dict(sorted(tasks.items())) if isinstance(tasks, dict) else tasks}
    with open(path, "w", encoding="utf-8") as outfile:
        json.dump(payload, outfile, ensure_ascii=False, indent=2)
def update_summary_bool(path: str, summary: Dict[str, Any], key: str, val: bool) -> None:
    summary.setdefault("tasks", {})
    summary["tasks"][key] = bool(val)
    write_summary_bool(path, summary)
def load_summary_full(path: str) -> Dict[str, Any]:
    if os.path.exists(path):
        with open(path, "r", encoding="utf-8") as infile:
            try:
                data = json.load(infile)
                if isinstance(data, dict) and "tasks" in data and isinstance(data["tasks"], dict):
                    return data
            except json.JSONDecodeError:
                pass
    return {"tasks": {}}
def write_summary_full(path: str, summary: Dict[str, Any]) -> None:
    tasks = summary.get("tasks", {})
    payload = {"tasks": dict(sorted(tasks.items())) if isinstance(tasks, dict) else tasks}
    with open(path, "w", encoding="utf-8") as outfile:
        json.dump(payload, outfile, ensure_ascii=False, indent=2)
def update_summary_full(path: str, summary: Dict[str, Any], key: str, record: Dict[str, Any]) -> None:
    summary.setdefault("tasks", {})
    summary["tasks"][key] = record
    write_summary_full(path, summary)
###############################################################################
# Trajectory loading & normalization
###############################################################################
def _normalize_screenshot_file_by_dataset(raw: Any, dataset_tag: str) -> str:
    s = raw if isinstance(raw, str) else ""
    if not s:
        return ""
    # Your requested per-dataset rules:
    # - OSWorld & WAA: removeprefix("images/")
    # - AW: no removeprefix
    # - WebArena: removeprefix("images/") then prefix "trajectory/"
    if dataset_tag in ("OSWorld", "WAA", "MacOS"):
        s = s.removeprefix("images/")
    elif dataset_tag == "WebArena":
        s = s.removeprefix("images/")
        if s:
            s = f"trajectory/{s}"
    elif dataset_tag == "AW":
        pass
    else:
        # safe default: keep original
        pass
    return s
def normalize_trajectory_steps(
    traj_data: Dict[str, Any],
    traj_dir: str,
    dataset_tag: str,
) -> Tuple[List[Dict[str, Any]], Dict[int, Dict[str, Any]], List[Optional[str]]]:
    """
    Return:
      - agent_history_records: [{step_index(1-based), think, operation, action, raw_response, screenshot_file, ...}, ...]
      - step_lookup: step_index(1-based) -> record
      - image_paths: 1-based aligned list where image_paths[k] is screenshot for step k (image_paths[0] is None)
    """
    raw_steps = traj_data.get("trajectory")
    if not isinstance(raw_steps, list):
        raw_steps = traj_data.get("steps") if isinstance(traj_data.get("steps"), list) else None
    if not isinstance(raw_steps, list) or not raw_steps:
        raise ValueError("trajectory.json missing 'trajectory' (or empty).")
    agent_history_records: List[Dict[str, Any]] = []
    step_lookup: Dict[int, Dict[str, Any]] = {}
    image_paths: List[Optional[str]] = [None]
    for step_index, entry in enumerate(raw_steps, 1):
        if not isinstance(entry, dict):
            continue
        raw_response = entry.get("raw_response") or entry.get("response") or entry.get("raw") or ""
        think_text = (entry.get("think") or "").strip()
        operation_text = (entry.get("operation") or "").strip()
        action_text = (entry.get("action") or "").strip()
        if not (think_text and operation_text and action_text):
            t = extract_tag_content(raw_response, "think")
            o = extract_tag_content(raw_response, "operation")
            a = extract_tag_content(raw_response, "action")
            think_text = think_text or t
            operation_text = operation_text or o
            action_text = action_text or a
        if not (think_text and operation_text and action_text):
            qwen_think, qwen_operation, qwen_action = extract_qwen_sections(raw_response)
            think_text = think_text or qwen_think
            operation_text = operation_text or qwen_operation
            action_text = action_text or qwen_action
        screenshot_file_raw = entry.get("screenshot_file") or entry.get("screenshot") or entry.get("image") or ""
        screenshot_file = _normalize_screenshot_file_by_dataset(screenshot_file_raw, dataset_tag)
        screenshot_abs: Optional[str] = None
        if isinstance(screenshot_file, str) and screenshot_file:
            screenshot_abs = screenshot_file if os.path.isabs(screenshot_file) else os.path.abspath(os.path.join(traj_dir, screenshot_file))
        image_paths.append(screenshot_abs)
        record = {
            "step_index": step_index,
            "orig_step_num": entry.get("step_num") or entry.get("step") or entry.get("step_index"),
            "think": think_text,
            "operation": operation_text,
            "action": action_text,
            "raw_response": raw_response,
            "screenshot_file": screenshot_file,
        }
        agent_history_records.append(record)
        step_lookup[step_index] = record
    return agent_history_records, step_lookup, image_paths
def infer_task_goal(traj_data: Dict[str, Any]) -> str:
    for k in ("query", "goal", "instruction", "task_goal", "prompt"):
        v = traj_data.get(k)
        if isinstance(v, str) and v.strip():
            return v.strip()
    return "Unknown goal"
def infer_task_id(traj_data: Dict[str, Any], traj_path: str) -> str:
    for k in ("task_id", "task_name", "id", "name"):
        v = traj_data.get(k)
        if isinstance(v, str) and v.strip():
            return v.strip()
    return os.path.basename(os.path.dirname(traj_path)) or "unknown_task"
def make_output_subdir(output_dir: str, task_id: str, traj_abs_path: str) -> str:
    digest = hashlib.md5(traj_abs_path.encode("utf-8")).hexdigest()[:10]
    safe_task = re.sub(r"[^A-Za-z0-9._-]+", "_", task_id)[:80]
    subdir = os.path.join(output_dir, f"{safe_task}__{digest}")
    ensure_output_dir(subdir)
    return subdir
###############################################################################
# Metrics
###############################################################################
def compute_metrics(tp: int, fp: int, tn: int, fn: int) -> Dict[str, float]:
    total = tp + fp + tn + fn
    acc = (tp + tn) / total if total else 0.0
    precision = tp / (tp + fp) if (tp + fp) else 0.0
    recall = tp / (tp + fn) if (tp + fn) else 0.0
    f1 = (2 _precision_ recall) / (precision + recall) if (precision + recall) else 0.0
    specificity = tn / (tn + fp) if (tn + fp) else 0.0
    balanced_acc = (recall + specificity) / 2.0
    return {
        "accuracy": acc,
        "precision": precision,
        "recall": recall,
        "f1": f1,
        "specificity": specificity,
        "balanced_accuracy": balanced_acc,
    }
###############################################################################
# Multi-agent core (per-trajectory)
###############################################################################
def run_task_on_trajectory(
    traj_abs_path: str,
    traj_display_path: str,
    gt_success: bool,
    mode: str,
    proposed_next_action: Optional[str],
    output_dir: str,
    summary_root_for_relpath: str,
    basic: str,
    model_name: str,
    dataset_tag: str,
) -> Dict[str, Any]:
    selector_model = SelectorModel(api_base=base_url, api_key=api_key, model_name=model_name, basic=basic)
    verifier_model = VerifierModel(api_base=base_url, api_key=api_key, model_name=model_name, basic=basic)
    final_judge_model = FinalJudgeModel(api_base=base_url, api_key=api_key, model_name=model_name, basic=basic)
    traj_dir = os.path.dirname(traj_abs_path)
    with open(traj_abs_path, "r", encoding="utf-8") as f:
        traj_data = json.load(f)
    task_goal = infer_task_goal(traj_data)
    task_id = infer_task_id(traj_data, traj_abs_path)
    agent_history_records, step_lookup, screenshots_1based = normalize_trajectory_steps(traj_data, traj_dir, dataset_tag)
    agent_history_str = format_json_for_prompt([
        {k: v for k, v in r.items() if k in ("step_index", "think", "operation", "action", "raw_response")}
        for r in agent_history_records
    ])
    task_output_dir = make_output_subdir(output_dir, task_id, traj_abs_path)
    print(f"[{dataset_tag}][{task_id}] Loaded {len(agent_history_records)} steps. Traj={traj_abs_path}")
    # -------------------------------
    # Next-action mode (optional)
    # -------------------------------
    if mode in ("next_action", "all"):
        conversation_log: List[Dict[str, Any]] = []
        selector_conversation_state: Dict[str, Any] = {}
        last_step = agent_history_records[-1] if agent_history_records else {}
        fallback_next_action = (last_step.get("operation") or "").strip() or "Not provided."
        next_action_text = (proposed_next_action or "").strip() or fallback_next_action
        current_ui_status = format_json_for_prompt(last_step) if last_step else "Unknown."
        selector_prompt = selector_model.build_next_action_prompt(
            task_goal=task_goal,
            agent_history=agent_history_str,
            proposed_next_action=next_action_text,
        )
        selector_messages = selector_model.prompt_to_message(
            selector_prompt, system_prompt=selector_model.get_next_action_system_prompt()
        )
        selector_raw = selector_model.act(selector_messages)
        append_conversation_entry(conversation_log, "SelectorModel", selector_raw, selector_conversation_state)
        selector_output = safe_parse_response(selector_model, selector_raw) or {}
        verifier_prompt = verifier_model.build_next_action_prompt(
            task_goal=task_goal,
            agent_history=agent_history_str,
            proposed_next_action=next_action_text,
            current_ui_status=current_ui_status,
        )
        verifier_messages = verifier_model.prompt_to_message(
            verifier_prompt, system_prompt=verifier_model.get_next_action_system_prompt()
        )
        verifier_raw = verifier_model.act(verifier_messages)
        append_conversation_entry(conversation_log, "VerifierModel", verifier_raw, selector_conversation_state)
        verifier_output = safe_parse_response(verifier_model, verifier_raw) or {}
        available_conversation = build_available_conversation(conversation_log)
        model_evidence = format_json_for_prompt(available_conversation)
        final_prompt = final_judge_model.build_next_action_prompt(
            task_goal=task_goal,
            agent_history=agent_history_str,
            proposed_next_action=next_action_text,
            model_evidence=model_evidence,
        )
        final_messages = final_judge_model.prompt_to_message(
            final_prompt, system_prompt=final_judge_model.get_next_action_system_prompt()
        )
        final_raw = final_judge_model.act(final_messages)
        append_conversation_entry(conversation_log, "FinalJudgeModel", final_raw, selector_conversation_state)
        final_output = safe_parse_response(final_judge_model, final_raw) or {}
        final_decision = final_output.get("next_action_decision", "uncertain")
        artifact = {
            "mode": "next_action",
            "task_id": task_id,
            "task_goal": task_goal,
            "dataset": dataset_tag,
            "trajectory_path": traj_display_path,
            "gt_success": bool(gt_success),
            "proposed_next_action": next_action_text,
            "selector": {"prompt": selector_prompt, "system_prompt": selector_model.get_next_action_system_prompt(), "raw_response": selector_raw, "parsed": selector_output},
            "verifier": {"prompt": verifier_prompt, "system_prompt": verifier_model.get_next_action_system_prompt(), "raw_response": verifier_raw, "parsed": verifier_output},
            "final_judge": {"prompt": final_prompt, "system_prompt": final_judge_model.get_next_action_system_prompt(), "raw_response": final_raw, "parsed": final_output},
            "conversation_log": conversation_log,
        }
        output_path = os.path.join(task_output_dir, "multi_agent_log_next_action.json")
        with open(output_path, "w", encoding="utf-8") as outfile:
            json.dump(artifact, outfile, ensure_ascii=False, indent=2)
        compact_na = {
            "gt_success": bool(gt_success),
            "pred_success": False,
            "model_responses": build_all_model_responses(conversation_log),
        }
        compact_na_path = os.path.join(task_output_dir, "multi_agent_log_compact_next_action.json")
        with open(compact_na_path, "w", encoding="utf-8") as outfile:
            json.dump(compact_na, outfile, ensure_ascii=False, indent=2)
        if mode == "next_action":
            return {
                "task_id": task_id,
                "trajectory_path": traj_display_path,
                "mode": "next_action",
                "final_decision": final_decision,
                "final_output": final_output,
                "final_raw": final_raw,
                "log_path": safe_relpath(output_path, summary_root_for_relpath),
                "compact_log_path": safe_relpath(compact_na_path, summary_root_for_relpath),
                "pred_success": False,
                "gt_success": bool(gt_success),
            }
    # -------------------------------
    # Completion mode
    # -------------------------------
    initial_system_prompt = selector_model.get_system_prompt()
    initial_prompt_base = selector_model.build_user_prompt(task_goal=task_goal, agent_history=agent_history_str)
    conversation_log: List[Dict[str, Any]] = []
    selector_conversation_state: Dict[str, Any] = {}
    initial_attempt_records: List[Dict[str, Any]] = []
    initial_selection: Optional[Dict[str, Any]] = None
    pending_key_steps: List[Dict[str, Any]] = []
    fallback_used = False
    fallback_steps: List[Dict[str, Any]] = []
    final_selector_package: Optional[Dict[str, Any]] = None
    for attempt in range(MAX_SELECTOR_INITIAL_RETRIES + 1):
        if attempt == 0:
            attempt_prompt = initial_prompt_base
        else:
            attempt_prompt = (
                f"{initial_prompt_base}\n\n"
                "RETRY INSTRUCTION: Your previous response was invalid because it did not include any key_steps entries. "
                "Respond with valid JSON containing a comprehensive key_steps array (each item must include step_index, assessment_goal, and why_important). "
                "When uncertain, choose MORE steps — cover every granular action needed to confirm or refute task completion."
            )
        attempt_messages = selector_model.prompt_to_message(attempt_prompt)
        attempt_raw = selector_model.act(attempt_messages)
        print(f"[{dataset_tag}][{task_id}] Selector initial response (attempt {attempt + 1}): {attempt_raw}")
        append_conversation_entry(conversation_log, "SelectorModel", attempt_raw, selector_conversation_state)
        parsed_attempt = safe_parse_response(selector_model, attempt_raw)
        initial_attempt_records.append({
            "attempt": attempt + 1,
            "user_prompt": attempt_prompt,
            "raw_response": attempt_raw,
            "parsed_response": parsed_attempt,
        })
        direct_handoff_used = False
        if isinstance(parsed_attempt, dict) and "need_more_steps" in parsed_attempt:
            if not parsed_attempt.get("need_more_steps"):
                candidate_package = parsed_attempt.get("final_or_handoff")
                reason_to_stop = parsed_attempt.get("reason_to_stop")
                if isinstance(candidate_package, dict):
                    final_selector_package = candidate_package
                if final_selector_package is None and reason_to_stop:
                    final_selector_package = {"reason_to_stop": reason_to_stop}
                initial_selection = parsed_attempt
                pending_key_steps = []
                direct_handoff_used = True
                print(f"[{dataset_tag}][{task_id}] Selector stopped selection without verification (attempt {attempt + 1}).")
                break
        pending_key_steps = normalize_key_steps(parsed_attempt)
        if pending_key_steps:
            initial_selection = parsed_attempt
            break
        if direct_handoff_used:
            break
        if attempt < MAX_SELECTOR_INITIAL_RETRIES:
            print(f"[{dataset_tag}][{task_id}] Selector initial attempt {attempt + 1} missing key_steps; retrying.")
        else:
            print(f"[{dataset_tag}][{task_id}] Selector initial attempt {attempt + 1} missing key_steps; no retries left.")
    if not pending_key_steps and final_selector_package is None:
        fallback_steps = build_fallback_key_steps(step_lookup)
        if fallback_steps:
            pending_key_steps = fallback_steps
            fallback_used = True
            print(f"[{dataset_tag}][{task_id}] Using fallback key steps due to selector failure: {fallback_steps}")
        else:
            raise ValueError("Selector initial response missing key_steps after retries.")
    if initial_selection is None and initial_attempt_records:
        initial_selection = initial_attempt_records[-1]["parsed_response"]
    processed_steps: set[int] = set()
    verification_counts: Dict[int, int] = {}
    verification_budgets: Dict[int, int] = {}
    reverified_steps: set[int] = set()
    verifier_results_by_step: Dict[int, Dict[str, Any]] = {}
    def remaining_verification_budget(step_index: Optional[int]) -> int:
        if step_index is None:
            return 0
        allowed = verification_budgets.get(step_index, 1)
        used = verification_counts.get(step_index, 0)
        return allowed - used
    def record_step_verification(step_index: Optional[int]) -> None:
        if step_index is None:
            return
        verification_counts[step_index] = verification_counts.get(step_index, 0) + 1
        if remaining_verification_budget(step_index) <= 0:
            processed_steps.add(step_index)
        else:
            processed_steps.discard(step_index)
    def allow_single_reverify(step_index: Optional[int]) -> bool:
        if step_index is None:
            return False
        if step_index in reverified_steps:
            return False
        previous_budget = verification_budgets.get(step_index, 1)
        if previous_budget >= 2:
            return False
        reverified_steps.add(step_index)
        verification_budgets[step_index] = 2
        processed_steps.discard(step_index)
        return True
    final_initial_prompt = initial_attempt_records[-1]["user_prompt"] if initial_attempt_records else initial_prompt_base
    final_initial_raw = initial_attempt_records[-1]["raw_response"] if initial_attempt_records else ""
    artifact: Dict[str, Any] = {
        "mode": "completion",
        "task_id": task_id,
        "task_goal": task_goal,
        "dataset": dataset_tag,
        "trajectory_path": traj_display_path,
        "gt_success": bool(gt_success),
        "agent_history": agent_history_records,
        "selector": {
            "initial": {
                "system_prompt": initial_system_prompt,
                "original_user_prompt": initial_prompt_base,
                "final_user_prompt": final_initial_prompt,
                "raw_response": final_initial_raw,
                "parsed_response": initial_selection,
                "attempts": initial_attempt_records,
                "fallback_used": fallback_used,
                "fallback_key_steps": fallback_steps if fallback_used else [],
            },
            "followups": [],
        },
        "verifier_calls": [],
        "final_selector_package": None,
        "final_judge": {},
        "conversation_log": conversation_log,
    }
    def verify_steps_batch(steps_to_process: List[Dict[str, Any]]) -> None:
        for step_entry in steps_to_process:
            step_index = step_entry.get("step_index")
            if step_index is None:
                continue
            try:
                step_index_int = int(step_index)
            except (TypeError, ValueError):
                continue
            if remaining_verification_budget(step_index_int) <= 0:
                continue
            step_record = step_lookup.get(step_index_int)
            if not step_record:
                print(f"[{dataset_tag}][{task_id}] Step {step_index_int} not found in trajectory.")
                processed_steps.add(step_index_int)
                continue
            assessment_goal = step_entry.get("assessment_goal", "") or ""
            before_image, after_image = get_step_image_pair(screenshots_1based, step_index_int)
            rel_before = safe_relpath(before_image, traj_dir)
            rel_after = safe_relpath(after_image, traj_dir)
            history_subset_records = agent_history_records[:step_index_int]
            history_subset = format_json_for_prompt(history_subset_records)
            after_image_status = (
                "after image available"
                if after_image
                else "No AFTER image captured because this was the final recorded state."
            )
            verifier_prompt = verifier_model.build_user_prompt(
                task_goal=task_goal,
                step_index=str(step_index_int),
                assessment_goal=assessment_goal,
                think=step_record.get("think", ""),
                operation=step_record.get("operation", ""),
                action=step_record.get("action", ""),
                agent_history=history_subset,
                after_image_status=after_image_status,
            )
            image_inputs: List[str] = []
            if before_image and os.path.exists(before_image):
                image_inputs.append(before_image)
            else:
                print("!" _50 + "No images" + "!"_ 50)
            if after_image and os.path.exists(after_image):
                image_inputs.append(after_image)
            verifier_messages = verifier_model.prompt_to_message(verifier_prompt, image_inputs)
            verifier_raw = verifier_model.act(verifier_messages)
            print(f"[{dataset_tag}][{task_id}] Verifier response for step {step_index_int}: {verifier_raw}")
            append_conversation_entry(conversation_log, "VerifierModel", verifier_raw, selector_conversation_state)
            parsed_verifier = safe_parse_response(verifier_model, verifier_raw)
            result_entry: Dict[str, Any] = {
                "step_index": step_index_int,
                "assessment_goal": assessment_goal,
                "raw_text": verifier_raw,
            }
            if isinstance(parsed_verifier, dict):
                verified_steps = parsed_verifier.get("verified_steps")
                if isinstance(verified_steps, list) and verified_steps:
                    matched = None
                    for candidate in verified_steps:
                        if isinstance(candidate, dict) and candidate.get("step_index") == step_index_int:
                            matched = candidate
                            break
                    if not matched:
                        matched = verified_steps[0] if isinstance(verified_steps[0], dict) else None
                    if isinstance(matched, dict):
                        result_entry["verdict"] = matched.get("verdict")
                        result_entry["evidence"] = matched.get("evidence")
                        result_entry["notes"] = matched.get("notes")
                        if matched.get("assessment_goal"):
                            result_entry["assessment_goal"] = matched.get("assessment_goal")
                selector_feedback = parsed_verifier.get("selector_feedback")
                if selector_feedback:
                    result_entry["selector_feedback"] = selector_feedback
                overall_summary = parsed_verifier.get("overall_summary")
                if overall_summary:
                    result_entry["overall_summary"] = overall_summary
                result_entry["parsed_response"] = parsed_verifier
            verifier_results_by_step[step_index_int] = result_entry
            record_step_verification(step_index_int)
            artifact["verifier_calls"].append({
                "step_index": step_index_int,
                "system_prompt": verifier_model.get_system_prompt(),
                "user_prompt": verifier_prompt,
                "assessment_goal": assessment_goal,
                "before_image": rel_before,
                "after_image": rel_after,
                "after_image_status": after_image_status,
                "raw_response": verifier_raw,
                "parsed_response": parsed_verifier,
                "agent_history": history_subset,
            })
    selector_round = 0
    skip_selector_cycle = final_selector_package is not None and not pending_key_steps
    if skip_selector_cycle:
        print(f"[{dataset_tag}][{task_id}] Skipping verifier phase based on selector’s direct stop.")
    while not skip_selector_cycle and selector_round < MAX_SELECTOR_ROUNDS:
        selector_round += 1
        steps_to_process = [
            step for step in pending_key_steps
            if remaining_verification_budget(step.get("step_index")) > 0
        ]
        verify_steps_batch(steps_to_process)
        selector_model.switch_stage("following")
        follow_system_prompt = selector_model.get_system_prompt()
        verifier_results_payload = [
            verifier_results_by_step[idx] for idx in sorted(verifier_results_by_step.keys())
        ]
        follow_prompt_base = selector_model.build_user_prompt(
            task_goal=task_goal,
            agent_history=agent_history_str,
            verifier_model_results=format_json_for_prompt(verifier_results_payload),
        )
        follow_entry: Dict[str, Any] = {
            "system_prompt": follow_system_prompt,
            "base_user_prompt": follow_prompt_base,
            "attempts": [],
        }
        follow_decision: Optional[Dict[str, Any]] = None
        next_pending_key_steps: Optional[List[Dict[str, Any]]] = None
        for attempt in range(MAX_SELECTOR_FOLLOW_RETRIES + 1):
            if attempt == 0:
                attempt_prompt = follow_prompt_base
            else:
                attempt_prompt = (
                    f"{follow_prompt_base}\n\n"
                    "RETRY INSTRUCTION: Provide valid JSON. Either set need_more_steps=true with a thorough, non-empty key_steps array (each containing "
                    "step_index, assessment_goal, and why_important) or set need_more_steps=false with a clear reason_to_stop that ties evidence to the task goal (no completion verdict required)."
                )
            follow_messages = selector_model.prompt_to_message(attempt_prompt)
            follow_raw = selector_model.act(follow_messages)
            print(f"[{dataset_tag}][{task_id}] Selector follow-up response (attempt {attempt + 1}): {follow_raw}")
            append_conversation_entry(conversation_log, "SelectorModel", follow_raw, selector_conversation_state)
            parsed_follow = safe_parse_response(selector_model, follow_raw)
            follow_entry["attempts"].append({
                "attempt": attempt + 1,
                "user_prompt": attempt_prompt,
                "raw_response": follow_raw,
                "parsed_response": parsed_follow,
            })
            if not isinstance(parsed_follow, dict):
                continue
            need_more = parsed_follow.get("need_more_steps")
            if need_more:
                next_steps = normalize_key_steps(parsed_follow)
                if not next_steps:
                    continue
                unique_new_steps = [
                    step for step in next_steps
                    if remaining_verification_budget(step.get("step_index")) > 0
                ]
                if not unique_new_steps:
                    continue
                next_pending_key_steps = unique_new_steps
            else:
                next_pending_key_steps = None
            follow_decision = parsed_follow
            follow_entry.update({
                "user_prompt": attempt_prompt,
                "raw_response": follow_raw,
                "parsed_response": parsed_follow,
                "need_more_steps": bool(need_more),
                "normalized_key_steps": next_pending_key_steps,
            })
            break
        artifact["selector"]["followups"].append(follow_entry)
        if not follow_decision:
            break
        if follow_decision.get("need_more_steps"):
            pending_key_steps = next_pending_key_steps or []
            if not pending_key_steps:
                break
            continue
        if follow_decision.get("final_or_handoff"):
            final_selector_package = follow_decision.get("final_or_handoff")
        elif follow_decision.get("reason_to_stop"):
            final_selector_package = {"reason_to_stop": follow_decision.get("reason_to_stop")}
        break
    artifact["final_selector_package"] = final_selector_package
    # Final judge
    available_conversation_log = build_available_conversation(conversation_log)
    verified_history_payload = format_json_for_prompt(available_conversation_log)
    final_prompt = final_judge_model.build_user_prompt(
        task_goal=task_goal,
        verified_history=verified_history_payload,
        history=agent_history_str,
    )
    final_system_prompt = final_judge_model.get_system_prompt()
    final_messages = final_judge_model.prompt_to_message(final_prompt)
    final_raw = final_judge_model.act(final_messages)
    append_conversation_entry(conversation_log, "FinalJudgeModel", final_raw, selector_conversation_state)
    print(f"[{dataset_tag}][{task_id}] Final Judge response: {final_raw}")
    final_output = safe_parse_response(final_judge_model, final_raw) or {}
    final_decision = final_output.get("final_decision", "uncertain")
    pred_success = (final_decision == "completed")
    artifact["final_judge"] = {
        "system_prompt": final_system_prompt,
        "user_prompt": final_prompt,
        "raw_response": final_raw,
        "parsed_response": final_output,
    }
    artifact["conversation_log"] = conversation_log
    artifact["pred_success"] = bool(pred_success)
    detailed_path = os.path.join(task_output_dir, "multi_agent_log.json")
    with open(detailed_path, "w", encoding="utf-8") as outfile:
        json.dump(artifact, outfile, ensure_ascii=False, indent=2)
    compact_log = {
        "gt_success": bool(gt_success),
        "pred_success": bool(pred_success),
        "model_responses": build_all_model_responses(conversation_log),
    }
    compact_path = os.path.join(task_output_dir, "multi_agent_log_compact.json")
    with open(compact_path, "w", encoding="utf-8") as outfile:
        json.dump(compact_log, outfile, ensure_ascii=False, indent=2)
    return {
        "task_id": task_id,
        "trajectory_path": traj_display_path,
        "mode": "completion",
        "gt_success": bool(gt_success),
        "pred_success": bool(pred_success),
        "final_decision": final_decision,
        "final_output": final_output,
        "final_raw": final_raw,
        "log_path": safe_relpath(detailed_path, summary_root_for_relpath),
        "compact_log_path": safe_relpath(compact_path, summary_root_for_relpath),
    }
###############################################################################
# Benchmark runner (one jsonl)
###############################################################################
def run_one_benchmark(
    *,
    selected_trajs_path: str,
    output_dir: str,
    dataset_tag: str,
    model_name: str,
    mode: str,
    proposed_next_action: Optional[str],
    basic: str,
) -> None:
    selected_path = os.path.abspath(selected_trajs_path)
    selected_dir = os.path.dirname(selected_path)
    ensure_output_dir(output_dir)
    summary_bool_file = os.path.join(output_dir, "summary.json")
    summary_full_file = os.path.join(output_dir, "summary_full.json")
    metrics_file = os.path.join(output_dir, "metrics.json")
    selected_items = read_jsonl(selected_path)
    if not selected_items:
        print(f"[{dataset_tag}] No entries found in {selected_path}")
        return
    summary_bool = load_summary_bool(summary_bool_file)
    summary_full = load_summary_full(summary_full_file)
    processed_keys = set(summary_full.get("tasks", {}).keys())
    jobs: List[Tuple[str, str, bool, str]] = []
    for entry in selected_items:
        traj_path_raw = entry.get("trajectory_path") or entry.get("path") or ""
        gt_success = bool(entry.get("success", False))
        if not isinstance(traj_path_raw, str) or not traj_path_raw.strip():
            continue
        traj_path_raw = traj_path_raw.strip()
        traj_abs = resolve_path(traj_path_raw, selected_dir)
        if not traj_abs:
            continue
        key_abs = traj_abs
        if key_abs in processed_keys:
            continue
        traj_display = traj_path_raw if not os.path.isabs(traj_path_raw) else traj_abs
        jobs.append((traj_abs, traj_display, gt_success, key_abs))
    skipped = len(selected_items) - len(jobs)
    print(f"[{dataset_tag}] Selected entries: {len(selected_items)} | Skipped: {skipped} | To run: {len(jobs)}")
    print(f"[{dataset_tag}] Output dir: {output_dir}")
    print(f"[{dataset_tag}] Model: {model_name} | Mode: {mode} | MaxWorkers: {MAX_WORKERS}")
    tp = fp = tn = fn = 0
    for rec in summary_full.get("tasks", {}).values():
        if not isinstance(rec, dict):
            continue
        gt = bool(rec.get("gt_success", False))
        pred = bool(rec.get("pred_success", False))
        if pred and gt:
            tp += 1
        elif pred and not gt:
            fp += 1
        elif (not pred) and (not gt):
            tn += 1
        else:
            fn += 1
    total_prev = tp + fp + tn + fn
    if total_prev:
        m0 = compute_metrics(tp, fp, tn, fn)
        print(f"[{dataset_tag}] Resumed: total={total_prev} acc={m0['accuracy']:.4f}")
    if not jobs:
        m = compute_metrics(tp, fp, tn, fn)
        payload = {
            "updated_at": now_iso(),
            "dataset": dataset_tag,
            "mode": mode,
            "model_name": model_name,
            "counts": {"tp": tp, "fp": fp, "tn": tn, "fn": fn, "total": tp + fp + tn + fn},
            "metrics": m,
        }
        with open(metrics_file, "w", encoding="utf-8") as f:
            json.dump(payload, f, ensure_ascii=False, indent=2)
        print(f"[{dataset_tag}] No new jobs. Metrics refreshed at {metrics_file}")
        return
    with ThreadPoolExecutor(max_workers=MAX_WORKERS) as executor:
        future_to_meta = {}
        for traj_abs, traj_display, gt_success, key_abs in jobs:
            future = executor.submit(
                run_task_on_trajectory,
                traj_abs,
                traj_display,
                gt_success,
                mode,
                proposed_next_action,
                output_dir,
                os.getcwd(),
                basic,
                model_name,
                dataset_tag,
            )
            future_to_meta[future] = (key_abs, traj_abs, traj_display, gt_success)
        for future in as_completed(future_to_meta):
            key_abs, traj_abs, traj_display, gt_success = future_to_meta[future]
            try:
                result = future.result()
                pred_success = bool(result.get("pred_success", False))
                gt_success = bool(result.get("gt_success", gt_success))
                if pred_success and gt_success:
                    tp += 1
                elif pred_success and (not gt_success):
                    fp += 1
                elif (not pred_success) and (not gt_success):
                    tn += 1
                else:
                    fn += 1
                matched = (pred_success == gt_success)
                update_summary_bool(summary_bool_file, summary_bool, key_abs, matched)
                full_record = {
                    "trajectory_path": traj_display,
                    "gt_success": gt_success,
                    "pred_success": pred_success,
                    "matched": matched,
                    "final_decision": result.get("final_decision"),
                    "final_raw": result.get("final_raw"),
                    "final_output": result.get("final_output"),
                    "log_path": result.get("log_path"),
                    "compact_log_path": result.get("compact_log_path"),
                    "updated_at": now_iso(),
                    "task_id": result.get("task_id"),
                    "mode": result.get("mode"),
                    "dataset": dataset_tag,
                }
                update_summary_full(summary_full_file, summary_full, key_abs, full_record)
            except Exception as exc:
                print(f"[{dataset_tag}][ERROR] {traj_abs} failed: {exc}")
            m = compute_metrics(tp, fp, tn, fn)
            total = tp + fp + tn + fn
            print(
                f"[{dataset_tag}][Progress] {total} processed | "
                f"Acc={m['accuracy']:.4f} P={m['precision']:.4f} R={m['recall']:.4f} F1={m['f1']:.4f} | "
                f"TP={tp} FP={fp} TN={tn} FN={fn}"
            )
            payload = {
                "updated_at": now_iso(),
                "dataset": dataset_tag,
                "mode": mode,
                "model_name": model_name,
                "counts": {"tp": tp, "fp": fp, "tn": tn, "fn": fn, "total": total},
                "metrics": m,
            }
            with open(metrics_file, "w", encoding="utf-8") as f:
                json.dump(payload, f, ensure_ascii=False, indent=2)
    print(f"[{dataset_tag}] Done. Metrics saved to: {metrics_file}")
    print(f"[{dataset_tag}] Summaries saved to: {summary_bool_file} and {summary_full_file}")
###############################################################################
# Main
###############################################################################
def main() -> None:
    parser = argparse.ArgumentParser(description="Run fixed 4-benchmark evaluation; only model name required.")
    parser.add_argument("--model-name", required=True, help="Model name to evaluate, e.g., gpt-5-mini / qwen3-vl-235b.")
    parser.add_argument("--mode", choices=["completion", "next_action", "all"], default=DEFAULT_MODE, help="Evaluation mode to run.")
    parser.add_argument("--proposed-next-action", dest="proposed_next_action", default=os.getenv("PROPOSED_NEXT_ACTION", ""), help="Optional proposed next action text for next_action mode.")
    parser.add_argument("--benchmark-root", default="benchmark", help="Root dir containing OSWorld.jsonl / AndroidWorld.jsonl / WebArena.jsonl / WindowsAgentArena.jsonl.")
    parser.add_argument("--result-root", default="benchmark_result", help="Root dir for outputs (default: benchmark_result).")
    args = parser.parse_args()
    model_name = str(args.model_name).strip()
    if not model_name:
        raise ValueError("Empty --model-name")
    bench_root = os.path.abspath(args.benchmark_root)
    result_root = os.path.abspath(args.result_root)
    if not ak or not sk:
        raise RuntimeError("Missing KAPI credentials. Please set env vars: KAPI_AK and KAPI_SK.")
    basic = base64.b64encode(f"{ak}:{sk}".encode()).decode()
    benchmarks = [
        {
            "dataset": "OSWorld",
            "jsonl": os.path.join(bench_root, "OSWorld.jsonl"),
            "out": os.path.join(result_root, model_name, "OSWorld_v2"),
        },
        {
            "dataset": "AW",
            "jsonl": os.path.join(bench_root, "AndroidWorld.jsonl"),
            "out": os.path.join(result_root, model_name, "AW_v2"),
        },
        {
            "dataset": "WAA",
            "jsonl": os.path.join(bench_root, "WindowsAgentArena.jsonl"),
            "out": os.path.join(result_root, model_name, "WAA_v3"),
        },
        {
            "dataset": "WebArena",
            "jsonl": os.path.join(bench_root, "WebArena.jsonl"),
            "out": os.path.join(result_root, model_name, "WebArena_v3"),
        },
        {
            "dataset": "MacOS",
            "jsonl": os.path.join(bench_root, "MacOS.jsonl"),
            "out": os.path.join(result_root, model_name, "MacOS_v1"),
        },
    ]
    for b in benchmarks:
        dataset_tag = b["dataset"]
        selected_trajs_path = b["jsonl"]
        output_dir = b["out"]
        if not os.path.exists(selected_trajs_path):
            print(f"[{dataset_tag}] WARNING: benchmark file not found: {selected_trajs_path}. Skipping.")
            continue
        run_one_benchmark(
            selected_trajs_path=selected_trajs_path,
            output_dir=output_dir,
            dataset_tag=dataset_tag,
            model_name=model_name,
            mode=args.mode,
            proposed_next_action=(args.proposed_next_action or "").strip() or None,
            basic=basic,
        )
