def ensure_output_dir(path: str) -> None:
    os.makedirs(path, exist_ok=True)

def read_jsonl(path: str) -> List[Dict[str, Any]]:
    items: List[Dict[str, Any]] = []
    with open(path, "r", encoding="utf-8") as f:
        for line_no, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
            except json.JSONDecodeError as e:
                raise ValueError(f"Invalid JSONL at {path}:{line_no}: {e}")
            if isinstance(obj, dict):
                items.append(obj)
    return items

def resolve_path(maybe_path: str, base_dir: str) -> str:
    if not isinstance(maybe_path, str) or not maybe_path:
        return ""
    if os.path.isabs(maybe_path):
        return maybe_path
    return os.path.abspath(os.path.join(base_dir, maybe_path))

def safe_relpath(path: Optional[str], start: str) -> Optional[str]:
    if not path:
        return None
    try:
        return os.path.relpath(path, start)
    except Exception:
        return path

def extract_tag_content(response: str, tag: str) -> str:
    pattern = re.compile(rf"<{tag}>\s*(.*?)\s*</{tag}>", re.DOTALL)
    match = pattern.search(response or "")
    return match.group(1).strip() if match else ""

def extract_qwen_sections(response: str) -> Tuple[str, str, str]:
    if not isinstance(response, str):
        return "", "", ""
    def capture_block(label: str) -> str:
        pattern = re.compile(
            rf"{label}:\s*(.*?)(?:\n[A-Za-z ]+?:|<tool_call>|$)",
            re.DOTALL,
        )
        match = pattern.search(response)
        return match.group(1).strip() if match else ""
    think = capture_block("Thought")
    operation = capture_block("Action")
    tool_match = re.search(r"<tool_call>\s*(.*?)\s*</tool_call>", response, re.DOTALL)
    action = tool_match.group(1).strip() if tool_match else ""
    return think, operation, action

def safe_parse_response(model, raw_response: str) -> Optional[Any]:
    if isinstance(raw_response, (dict, list)):
        return raw_response
    try:
        return model.parse_response(raw_response)
    except Exception as exc:
        print(f"[{model.name}] Failed to parse response: {exc}\nRaw: {raw_response}")
        return None

def normalize_selector_response_text(text: Optional[str]) -> str:
    if not isinstance(text, str):
        return ""
    return " ".join(text.split())

def append_conversation_entry(
    conversation_log: List[Dict[str, Any]],
    model_name: str,
    text: str,
    selector_state: Dict[str, Any],
) -> None:
    available = True
    if model_name == "SelectorModel":
        normalized_text = normalize_selector_response_text(text)
        last_text = selector_state.get("last_text")
        waiting = selector_state.get("waiting_for_response", False)
        if waiting and normalized_text == last_text:
            available = False
        else:
            selector_state["last_text"] = normalized_text
        selector_state["waiting_for_response"] = True
    else:
        selector_state["waiting_for_response"] = False
    conversation_log.append({
        "model": model_name,
        "text": text,
        "available": available,
    })

