def format_json_for_prompt(data: Any) -> str:
    try:
        return json.dumps(data, ensure_ascii=False, indent=2)
    except (TypeError, ValueError):
        return json.dumps({"unserializable": True}, ensure_ascii=False)

def normalize_key_steps(selection: Optional[Dict[str, Any]]) -> List[Dict[str, Any]]:
    if not isinstance(selection, dict):
        return []
    normalized_steps: List[Dict[str, Any]] = []
    raw_key_steps = selection.get("key_steps")
    if isinstance(raw_key_steps, list):
        for item in raw_key_steps:
            if not isinstance(item, dict):
                continue
            step_index = item.get("step_index")
            try:
                step_index_int = int(step_index)
            except (TypeError, ValueError):
                continue
            goal = (item.get("assessment_goal") or "").strip()
            why = (item.get("why_important") or "").strip()
            normalized_steps.append({
                "step_index": step_index_int,
                "assessment_goal": goal,
                "why_important": why,
            })
    if not normalized_steps:
        legacy_indices = selection.get("key_step_indices")
        if isinstance(legacy_indices, list):
            for idx in legacy_indices:
                try:
                    step_index_int = int(idx)
                except (TypeError, ValueError):
                    continue
                normalized_steps.append({
                    "step_index": step_index_int,
                    "assessment_goal": "",
                    "why_important": "",
                })
    deduped: List[Dict[str, Any]] = []
    seen: set[int] = set()
    for step in normalized_steps:
        idx = step["step_index"]
        if idx in seen:
            continue
        seen.add(idx)
        deduped.append(step)
    return deduped

def build_fallback_key_steps(
    step_lookup: Dict[int, Dict[str, Any]],
    max_steps: int = FALLBACK_KEY_STEPS_COUNT
) -> List[Dict[str, Any]]:
    if not step_lookup:
        return []
    sorted_indices = sorted(idx for idx in step_lookup.keys() if isinstance(idx, int))
    if not sorted_indices:
        return []
    terminal_step = sorted_indices[-1]
    candidate_indices = [idx for idx in sorted_indices if idx < terminal_step] or sorted_indices
    selected_indices = candidate_indices[-max_steps:]
    fallback_steps: List[Dict[str, Any]] = []
    for idx in selected_indices:
        record = step_lookup.get(idx, {})
        operation_desc = (
            record.get("operation")
            or record.get("action")
            or record.get("think")
            or ""
        )
        operation_desc = (operation_desc or "").strip()
        if len(operation_desc) > 160:
            operation_desc = operation_desc[:157] + "..."
        assessment_goal = f"Confirm that step {idx} achieved its intent: {operation_desc or 'intended operation'}."
        fallback_steps.append({
            "step_index": idx,
            "assessment_goal": assessment_goal,
            "why_important": "Fallback coverage for decisive recent steps.",
        })
    return fallback_steps

def get_step_image_pair(image_paths_1based: List[Optional[str]], step_index_1based: int) -> Tuple[Optional[str], Optional[str]]:
    if not image_paths_1based or len(image_paths_1based) <= 1:
        return None, None
    before_idx = step_index_1based
    after_idx = step_index_1based + 1
    before_path = image_paths_1based[before_idx] if 1 <= before_idx < len(image_paths_1based) else None
    after_path = image_paths_1based[after_idx] if 1 <= after_idx < len(image_paths_1based) else None
    print(f"step:{step_index_1based}, before_idx:{before_idx}, after_idx:{after_idx}, len:{len(image_paths_1based)}, before_path:{before_path}, after_path:{after_path}")
    return before_path, after_path

def load_summary_bool(path: str) -> Dict[str, Any]:
    if os.path.exists(path):
        with open(path, "r", encoding="utf-8") as infile:
            try:
                data = json.load(infile)
                if isinstance(data, dict):
                    if "tasks" in data and isinstance(data["tasks"], dict):
                        return data
                    if all(isinstance(v, bool) for v in data.values()):
                        return {"tasks": data}
            except json.JSONDecodeError:
                pass
    return {"tasks": {}}

def write_summary_bool(path: str, summary: Dict[str, Any]) -> None:
    tasks = summary.get("tasks", {})
    payload = {"tasks": dict(sorted(tasks.items())) if isinstance(tasks, dict) else tasks}
    with open(path, "w", encoding="utf-8") as outfile:
        json.dump(payload, outfile, ensure_ascii=False, indent=2)

def update_summary_bool(path: str, summary: Dict[str, Any], key: str, val: bool) -> None:
    summary.setdefault("tasks", {})
    summary["tasks"][key] = bool(val)
    write_summary_bool(path, summary)

