def _normalize_screenshot_file_by_dataset(raw: Any, dataset_tag: str) -> str:
    s = raw if isinstance(raw, str) else ""
    if not s:
        return ""
    if dataset_tag in ("OSWorld", "WAA", "MacOS"):
        s = s.removeprefix("images/")
    elif dataset_tag == "WebArena":
        s = s.removeprefix("images/")
        if s:
            s = f"trajectory/{s}"
    elif dataset_tag == "AW":
        pass
    else:
        pass
    return s

def normalize_trajectory_steps(
    traj_data: Dict[str, Any],
    traj_dir: str,
    dataset_tag: str,
) -> Tuple[List[Dict[str, Any]], Dict[int, Dict[str, Any]], List[Optional[str]]]:
    raw_steps = traj_data.get("trajectory")
    if not isinstance(raw_steps, list):
        raw_steps = traj_data.get("steps") if isinstance(traj_data.get("steps"), list) else None
    if not isinstance(raw_steps, list) or not raw_steps:
        raise ValueError("trajectory.json missing 'trajectory' (or empty).")
    agent_history_records: List[Dict[str, Any]] = []
    step_lookup: Dict[int, Dict[str, Any]] = {}
    image_paths: List[Optional[str]] = [None]
    for step_index, entry in enumerate(raw_steps, 1):
        if not isinstance(entry, dict):
            continue
        raw_response = entry.get("raw_response") or entry.get("response") or entry.get("raw") or ""
        think_text = (entry.get("think") or "").strip()
        operation_text = (entry.get("operation") or "").strip()
        action_text = (entry.get("action") or "").strip()
        if not (think_text and operation_text and action_text):
            t = extract_tag_content(raw_response, "think")
            o = extract_tag_content(raw_response, "operation")
            a = extract_tag_content(raw_response, "action")
            think_text = think_text or t
            operation_text = operation_text or o
            action_text = action_text or a
        if not (think_text and operation_text and action_text):
            qwen_think, qwen_operation, qwen_action = extract_qwen_sections(raw_response)
            think_text = think_text or qwen_think
            operation_text = operation_text or qwen_operation
            action_text = action_text or qwen_action
        screenshot_file_raw = entry.get("screenshot_file") or entry.get("screenshot") or entry.get("image") or ""
        screenshot_file = _normalize_screenshot_file_by_dataset(screenshot_file_raw, dataset_tag)
        screenshot_abs: Optional[str] = None
        if isinstance(screenshot_file, str) and screenshot_file:
            screenshot_abs = screenshot_file if os.path.isabs(screenshot_file) else os.path.abspath(os.path.join(traj_dir, screenshot_file))
        image_paths.append(screenshot_abs)
        record = {
            "step_index": step_index,
            "orig_step_num": entry.get("step_num") or entry.get("step") or entry.get("step_index"),
            "think": think_text,
            "operation": operation_text,
            "action": action_text,
            "raw_response": raw_response,
            "screenshot_file": screenshot_file,
        }
        agent_history_records.append(record)
        step_lookup[step_index] = record
    return agent_history_records, step_lookup, image_paths

def infer_task_goal(traj_data: Dict[str, Any]) -> str:
    for k in ("query", "goal", "instruction", "task_goal", "prompt"):
        v = traj_data.get(k)
        if isinstance(v, str) and v.strip():
            return v.strip()
    return "Unknown goal"

def infer_task_id(traj_data: Dict[str, Any], traj_path: str) -> str:
    for k in ("task_id", "task_name", "id", "name"):
        v = traj_data.get(k)
        if isinstance(v, str) and v.strip():
            return v.strip()
    return os.path.basename(os.path.dirname(traj_path)) or "unknown_task"

def make_output_subdir(output_dir: str, task_id: str, traj_abs_path: str) -> str:
    digest = hashlib.md5(traj_abs_path.encode("utf-8")).hexdigest()[:10]
    safe_task = re.sub(r"[^A-Za-z0-9._-]+", "_", task_id)[:80]
    subdir = os.path.join(output_dir, f"{safe_task}__{digest}")
    ensure_output_dir(subdir)
    return subdir

def compute_metrics(tp: int, fp: int, tn: int, fn: int) -> Dict[str, float]:
    total = tp + fp + tn + fn
    acc = (tp + tn) / total if total else 0.0
    precision = tp / (tp + fp) if (tp + fp) else 0.0
    recall = tp / (tp + fn) if (tp + fn) else 0.0
    f1 = (2 * precision * recall) / (precision + recall) if (precision + recall) else 0.0
    specificity = tn / (tn + fp) if (tn + fp) else 0.0
    balanced_acc = (recall + specificity) / 2.0
    return {
        "accuracy": acc,
        "precision": precision,
        "recall": recall,
        "f1": f1,
        "specificity": specificity,
        "balanced_accuracy": balanced_acc,
    }

def run_task_on_trajectory(
    traj_abs_path: str,
    traj_display_path: str,
    gt_success: bool,
    mode: str,
    proposed_next_action: Optional[str],
    output_dir: str,
    summary_root_for_relpath: str,
    basic: str,
    model_name: str,
    dataset_tag: str,
) -> Dict[str, Any]:
    selector_model = SelectorModel(api_base=base_url, api_key=api_key, model_name=model_name, basic=basic)
    verifier_model = VerifierModel(api_base=base_url, api_key=api_key, model_name=model_name, basic=basic)
    final_judge_model = FinalJudgeModel(api_base=base_url, api_key=api_key, model_name=model_name, basic=basic)
    traj_dir = os.path.dirname(traj_abs_path)
    with open(traj_abs_path, "r", encoding="utf-8") as f:
        traj_data = json.load(f)
    task_goal = infer_task_goal(traj_data)
    task_id = infer_task_id(traj_data, traj_abs_path)
    agent_history_records, step_lookup, screenshots_1based = normalize_trajectory_steps(traj_data, traj_dir, dataset_tag)
    agent_history_str = format_json_for_prompt([
        {k: v for k, v in r.items() if k in ("step_index", "think", "operation", "action", "raw_response")}
        for r in agent_history_records
    ])
    task_output_dir = make_output_subdir(output_dir, task_id, traj_abs_path)
    print(f"[{dataset_tag}][{task_id}] Loaded {len(agent_history_records)} steps. Traj={traj_abs_path}")

    if mode in ("next_action", "all"):
        conversation_log: List[Dict[str, Any]] = []
        selector_conversation_state: Dict[str, Any] = {}
        last_step = agent_history_records[-1] if agent_history_records else {}
        fallback_next_action = (last_step.get("operation") or "").strip() or "Not provided."
        next_action_text = (proposed_next_action or "").strip() or fallback_next_action
        current_ui_status = format_json_for_prompt(last_step) if last_step else "Unknown."
        selector_prompt = selector_model.build_next_action_prompt(
            task_goal=task_goal,
            agent_history=agent_history_str,
            proposed_next_action=next_action_text,
        )
        selector_messages = selector_model.prompt_to_message(
            selector_prompt, system_prompt=selector_model.get_next_action_system_prompt()
        )
        selector_raw = selector_model.act(selector_messages)
        append_conversation_entry(conversation_log, "SelectorModel", selector_raw, selector_conversation_state)
        selector_output = safe_parse_response(selector_model, selector_raw) or {}
        verifier_prompt = verifier_model.build_next_action_prompt(
            task_goal=task_goal,
            agent_history=agent_history_str,
            proposed_next_action=next_action_text,
            current_ui_status=current_ui_status,
        )
        verifier_messages = verifier_model.prompt_to_message(
            verifier_prompt, system_prompt=verifier_model.get_next_action_system_prompt()
        )
        verifier_raw = verifier_model.act(verifier_messages)
        append_conversation_entry(conversation_log, "VerifierModel", verifier_raw, selector_conversation_state)
        verifier_output = safe_parse_response(verifier_model, verifier_raw) or {}
        available_conversation = build_available_conversation(conversation_log)
        model_evidence = format_json_for_prompt(available_conversation)
        final_prompt = final_judge_model.build_next_action_prompt(
            task_goal=task_goal,
            agent_history=agent_history_str,
            proposed_next_action=next_action_text,
            model_evidence=model_evidence,
        )
        final_messages = final_judge_model.prompt_to_message(
            final_prompt, system_prompt=final_judge_model.get_next_action_system_prompt()
        )
        final_raw = final_judge_model.act(final_messages)
        append_conversation_entry(conversation_log, "FinalJudgeModel", final_raw, selector_conversation_state)
        final_output = safe_parse_response(final_judge_model, final_raw) or {}
        final_decision = final_output.get("next_action_decision", "uncertain")
        artifact = {
            "mode": "next_action",
            "task_id": task_id,
            "task_goal": task_goal,
            "dataset": dataset_tag,
            "trajectory_path": traj_display_path,
            "gt_success": bool(gt_success),
            "proposed_next_action": next_action_text,
            "selector": {"prompt": selector_prompt, "system_prompt": selector_model.get_next_action_system_prompt(), "raw_response": selector_raw, "parsed": selector_output},
            "verifier": {"prompt": verifier_prompt, "system_prompt": verifier_model.get_next_action_system_prompt(), "raw_response": verifier_raw, "parsed": verifier_output},
            "final_judge": {"prompt": final_prompt, "system_prompt": final_judge_model.get_next_action_system_prompt(), "raw_response": final_raw, "parsed": final_output},
            "conversation_log": conversation_log,
        }
        output_path = os.path.join(task_output_dir, "multi_agent_log_next_action.json")
        with open(output_path, "w", encoding="utf-8") as outfile:
            json.dump(artifact, outfile, ensure_ascii=False, indent=2)
        compact_na = {
            "gt_success": bool(gt_success),
            "pred_success": False,
            "model_responses": build_all_model_responses(conversation_log),
        }
        compact_na_path = os.path.join(task_output_dir, "multi_agent_log_compact_next_action.json")
        with open(compact_na_path, "w", encoding="utf-8") as outfile:
            json.dump(compact_na, outfile, ensure_ascii=False, indent=2)
        if mode == "next_action":
            return {
                "task_id": task_id,
                "trajectory_path": traj_display_path,
                "mode": "next_action",
                "final_decision": final_decision,
                "final_output": final_output,
                "final_raw": final_raw,
                "log_path": safe_relpath(output_path, summary_root_for_relpath),
                "compact_log_path": safe_relpath(compact_na_path, summary_root_for_relpath),
                "pred_success": False,
                "gt_success": bool(gt_success),
            }

    initial_system_prompt = selector_model.get_system_prompt()
    initial_prompt_base = selector_model.build_user_prompt(task_goal=task_goal, agent_history=agent_history_str)
    conversation_log: List[Dict[str, Any]] = []
    selector_conversation_state: Dict[str, Any] = {}
    initial_attempt_records: List[Dict[str, Any]] = []
    initial_selection: Optional[Dict[str, Any]] = None
    pending_key_steps: List[Dict[str, Any]] = []
    fallback_used = False
    fallback_steps: List[Dict[str, Any]] = []
    final_selector_package: Optional[Dict[str, Any]] = None
    for attempt in range(MAX_SELECTOR_INITIAL_RETRIES + 1):
        if attempt == 0:
            attempt_prompt = initial_prompt_base
        else:
            attempt_prompt = (
                f"{initial_prompt_base}\n\n"
                "RETRY INSTRUCTION: Your previous response was invalid because it did not include any key_steps entries. "
                "Respond with valid JSON containing a comprehensive key_steps array (each item must include step_index, assessment_goal, and why_important). "
                "When uncertain, choose MORE steps — cover every granular action needed to confirm or refute task completion."
            )
        attempt_messages = selector_model.prompt_to_message(attempt_prompt)
        attempt_raw = selector_model.act(attempt_messages)
        print(f"[{dataset_tag}][{task_id}] Selector initial response (attempt {attempt + 1}): {attempt_raw}")
        append_conversation_entry(conversation_log, "SelectorModel", attempt_raw, selector_conversation_state)
        parsed_attempt = safe_parse_response(selector_model, attempt_raw)
        initial_attempt_records.append({
            "attempt": attempt + 1,
            "user_prompt": attempt_prompt,
            "raw_response": attempt_raw,
            "parsed_response": parsed_attempt,
        })
        direct_handoff_used = False
        if isinstance(parsed_attempt, dict) and "need_more_steps" in parsed_attempt:
            if not parsed_attempt.get("need_more_steps"):
                candidate_package = parsed_attempt.get("final_or_handoff")
                reason_to_stop = parsed_attempt.get("reason_to_stop")
                if isinstance(candidate_package, dict):
                    final_selector_package = candidate_package
                if final_selector_package is None and reason_to_stop:
                    final_selector_package = {"reason_to_stop": reason_to_stop}
                initial_selection = parsed_attempt
                pending_key_steps = []
                direct_handoff_used = True
                print(f"[{dataset_tag}][{task_id}] Selector stopped selection without verification (attempt {attempt + 1}).")
                break
        pending_key_steps = normalize_key_steps(parsed_attempt)
        if pending_key_steps:
            initial_selection = parsed_attempt
            break
        if direct_handoff_used:
            break
        if attempt < MAX_SELECTOR_INITIAL_RETRIES:
            print(f"[{dataset_tag}][{task_id}] Selector initial attempt {attempt + 1} missing key_steps; retrying.")
        else:
            print(f"[{dataset_tag}][{task_id}] Selector initial attempt {attempt + 1} missing key_steps; no retries left.")
    if not pending_key_steps and final_selector_package is None:
        fallback_steps = build_fallback_key_steps(step_lookup)
        if fallback_steps:
            pending_key_steps = fallback_steps
            fallback_used = True
